            module siso(clk,rst,a,q);



              input a;

              input clk,rst;

              output q;

              reg q;



              always@(posedge clk,posedge rst)

              begin



		if(rst==1'b1)



                  q<1'b0;


		else



                  q<a;



              end


            endmodule

module pipo(clk,rst,a,q);



  input clk,rst;

  input[3:0]a;

  output[3:0]q;

  reg[3:0]q;



  always@(posedge clk,posedge rst)

  begin



    if (rst==1'b1)



      q<4'b0000;


    else



      q<a;



  end


endmodule
